  1→"use client";
  2→
  3→import { useState, useCallback } from "react";
  4→
  5→interface DeployInfo {
  6→  projectId: string;
  7→  serviceId: string;
  8→  environmentId: string;
  9→  domain: string;
 10→  setupPassword: string;
 11→}
 12→
 13→interface DeployState {
 14→  deployInfo: DeployInfo | null;
 15→  deployStatus: string | null;
 16→  walletAddress: string | null;
 17→  error: string | null;
 18→  loading: boolean;
 19→}
 20→
 21→export function useAgentDeploy() {
 22→  const [state, setState] = useState<DeployState>({
 23→    deployInfo: null,
 24→    deployStatus: null,
 25→    walletAddress: null,
 26→    error: null,
 27→    loading: false,
 28→  });
 29→
 30→  const deployAgent = useCallback(
 31→    async (config: {
 32→      agentName: string;
 33→      telegramBotToken?: string;
 34→      telegramAllowedUsers?: string;
 35→    }) => {
 36→      setState((s) => ({ ...s, loading: true, error: null }));
 37→      try {
 38→        const res = await fetch("/api/agent/deploy", {
 39→          method: "POST",
 40→          headers: { "Content-Type": "application/json" },
 41→          body: JSON.stringify(config),
 42→        });
 43→        const data = await res.json();
 44→        if (data.error) throw new Error(data.error);
 45→
 46→        const info: DeployInfo = {
 47→          projectId: data.projectId,
 48→          serviceId: data.serviceId,
 49→          environmentId: data.environmentId,
 50→          domain: data.domain,
 51→          setupPassword: data.setupPassword,
 52→        };
 53→
 54→        setState((s) => ({
 55→          ...s,
 56→          deployInfo: info,
 57→          deployStatus: "DEPLOYING",
 58→          loading: false,
 59→        }));
 60→
 61→        return info;
 62→      } catch (err) {
 63→        const message =
 64→          err instanceof Error ? err.message : "Deploy failed";
 65→        setState((s) => ({ ...s, error: message, loading: false }));
 66→        return null;
 67→      }
 68→    },
 69→    []
 70→  );
 71→
 72→  const pollDeployStatus = useCallback(
 73→    async (serviceId: string, environmentId: string) => {
 74→      setState((s) => ({ ...s, loading: true }));
 75→      const maxAttempts = 60; // ~5 minutes with 5s intervals
 76→
 77→      for (let i = 0; i < maxAttempts; i++) {
 78→        try {
 79→          const res = await fetch(
 80→            `/api/agent/deploy/status?serviceId=${serviceId}&environmentId=${environmentId}`
 81→          );
 82→          const data = await res.json();
 83→
 84→          setState((s) => ({
 85→            ...s,
 86→            deployStatus: data.status,
 87→            walletAddress: data.walletAddress || s.walletAddress,
 88→          }));
 89→
 90→          if (data.status === "SUCCESS") {
 91→            setState((s) => ({ ...s, loading: false }));
 92→            return { status: "SUCCESS", walletAddress: data.walletAddress };
 93→          }
 94→
 95→          if (data.status === "FAILED" || data.status === "CRASHED") {
 96→            setState((s) => ({
 97→              ...s,
 98→              error: `Deployment ${data.status.toLowerCase()}`,
 99→              loading: false,
100→            }));
101→            return { status: data.status, walletAddress: null };
102→          }
103→        } catch {
104→          // retry
105→        }
106→
107→        await new Promise((r) => setTimeout(r, 5000));
108→      }
109→
110→      setState((s) => ({
111→        ...s,
112→        error: "Deployment timed out",
113→        loading: false,
114→      }));
115→      return { status: "TIMEOUT", walletAddress: null };
116→    },
117→    []
118→  );
119→
120→  const getAgentWallet = useCallback(async (agentUrl: string) => {
121→    try {
122→      const res = await fetch(`${agentUrl}/health`);
123→      const data = await res.json();
124→      if (data.walletAddress) {
125→        setState((s) => ({ ...s, walletAddress: data.walletAddress }));
126→        return data.walletAddress as string;
127→      }
128→    } catch {
129→      // Agent may not be ready yet
130→    }
131→    return null;
132→  }, []);
133→
134→  return {
135→    ...state,
136→    deployAgent,
137→    pollDeployStatus,
138→    getAgentWallet,
139→  };
140→}
