  1→import { NextRequest, NextResponse } from "next/server";
  2→import { createPublicClient, http, getAddress } from "viem";
  3→import { celo } from "viem/chains";
  4→import { PrivyClient } from "@privy-io/node";
  5→import { createViemAccount } from "@privy-io/node/viem";
  6→
  7→// Self Agent Registry on Celo mainnet
  8→const REGISTRY_ADDRESS = "0xaC3DF9ABf80d0F5c020C06B04Cced27763355944" as const;
  9→const CELO_RPC_URL = process.env.CELO_RPC_URL || "https://forno.celo.org";
 10→
 11→const REGISTRY_ABI = [
 12→  {
 13→    name: "walletSetNonces",
 14→    type: "function",
 15→    stateMutability: "view",
 16→    inputs: [{ name: "id", type: "uint256" }],
 17→    outputs: [{ name: "", type: "uint256" }],
 18→  },
 19→] as const;
 20→
 21→// EIP-712 types matching the registry's AgentWalletSet struct
 22→const EIP712_DOMAIN = {
 23→  name: "SelfAgentRegistry",
 24→  version: "1",
 25→  chainId: 42220, // Celo mainnet
 26→  verifyingContract: REGISTRY_ADDRESS,
 27→} as const;
 28→
 29→const AGENT_WALLET_SET_TYPES = {
 30→  AgentWalletSet: [
 31→    { name: "agentId", type: "uint256" },
 32→    { name: "newWallet", type: "address" },
 33→    { name: "owner", type: "address" },
 34→    { name: "nonce", type: "uint256" },
 35→    { name: "deadline", type: "uint256" },
 36→  ],
 37→} as const;
 38→
 39→function getPrivyClient() {
 40→  const appId = process.env.PRIVY_APP_ID;
 41→  const appSecret = process.env.PRIVY_APP_SECRET;
 42→  if (!appId || !appSecret) {
 43→    throw new Error("PRIVY_APP_ID and PRIVY_APP_SECRET must be set");
 44→  }
 45→  return new PrivyClient({ appId, appSecret });
 46→}
 47→
 48→/**
 49→ * POST /api/agent-id/delegate
 50→ *
 51→ * Signs the EIP-712 AgentWalletSet message with the Privy agent wallet (EOA),
 52→ * so the human can submit setAgentWallet on the Self registry.
 53→ *
 54→ * Body: { agentId: number, walletId: string, walletAddress: string, ownerAddress: string }
 55→ * Returns: { signature, newWallet, deadline, nonce }
 56→ */
 57→export async function POST(req: NextRequest) {
 58→  try {
 59→    const { agentId, walletId, walletAddress, ownerAddress } = await req.json();
 60→
 61→    if (agentId == null || !walletId || !walletAddress || !ownerAddress) {
 62→      return NextResponse.json(
 63→        { error: "Missing required fields: agentId, walletId, walletAddress, ownerAddress" },
 64→        { status: 400 }
 65→      );
 66→    }
 67→
 68→    const newWallet = getAddress(walletAddress);
 69→    const owner = getAddress(ownerAddress);
 70→
 71→    // Read current nonce from registry
 72→    const publicClient = createPublicClient({
 73→      chain: celo,
 74→      transport: http(CELO_RPC_URL),
 75→    });
 76→
 77→    const nonce = await publicClient.readContract({
 78→      address: REGISTRY_ADDRESS,
 79→      abi: REGISTRY_ABI,
 80→      functionName: "walletSetNonces",
 81→      args: [BigInt(agentId)],
 82→    });
 83→
 84→    // Deadline: 1 hour from now
 85→    const deadline = BigInt(Math.floor(Date.now() / 1000) + 3600);
 86→
 87→    // Create Privy-backed viem account for the agent wallet
 88→    const privy = getPrivyClient();
 89→    const account = await createViemAccount(privy, {
 90→      walletId,
 91→      address: newWallet,
 92→    });
 93→
 94→    // Sign EIP-712 typed data with the agent's Privy wallet
 95→    const signature = await account.signTypedData({
 96→      domain: EIP712_DOMAIN,
 97→      types: AGENT_WALLET_SET_TYPES,
 98→      primaryType: "AgentWalletSet",
 99→      message: {
100→        agentId: BigInt(agentId),
101→        newWallet,
102→        owner,
103→        nonce,
104→        deadline,
105→      },
106→    });
107→
108→    console.log("[agent-id/delegate] Signed AgentWalletSet", {
109→      agentId,
110→      newWallet,
111→      owner,
112→      nonce: nonce.toString(),
113→      deadline: deadline.toString(),
114→    });
115→
116→    return NextResponse.json({
117→      signature,
118→      newWallet,
119→      deadline: deadline.toString(),
120→      nonce: nonce.toString(),
121→    });
122→  } catch (err) {
123→    const message = err instanceof Error ? err.message : "Delegation signing failed";
124→    console.error("[agent-id/delegate] Error:", message);
125→    return NextResponse.json({ error: message }, { status: 500 });
126→  }
127→}
