  1→import { NextRequest, NextResponse } from "next/server";
  2→import { requestRegistration } from "@selfxyz/agent-sdk";
  3→
  4→const SELF_API_BASE = "https://app.ai.self.xyz";
  5→
  6→// Store active sessions server-side
  7→const activeSessions = new Map<
  8→  string,
  9→  {
 10→    sessionToken: string;
 11→    agentAddress: string;
 12→    result: {
 13→      status: string;
 14→      agentId?: number;
 15→      agentAddress?: string;
 16→      txHash?: string;
 17→      privateKey?: string;
 18→    } | null;
 19→    error: string | null;
 20→  }
 21→>();
 22→
 23→// Poll Self API with correct Bearer auth
 24→async function pollSelfStatus(sessionToken: string) {
 25→  const res = await fetch(`${SELF_API_BASE}/api/agent/register/status`, {
 26→    method: "GET",
 27→    headers: {
 28→      Authorization: `Bearer ${sessionToken}`,
 29→    },
 30→  });
 31→
 32→  if (!res.ok) {
 33→    const body = await res.json().catch(() => ({}));
 34→    throw new Error(
 35→      (body as { error?: string }).error || `HTTP ${res.status}`
 36→    );
 37→  }
 38→
 39→  return res.json();
 40→}
 41→
 42→// Background poller for a session
 43→async function backgroundPoll(sessionKey: string) {
 44→  const entry = activeSessions.get(sessionKey);
 45→  if (!entry) return;
 46→
 47→  const deadline = Date.now() + 300_000; // 5 min timeout
 48→  let currentToken = entry.sessionToken;
 49→
 50→  while (Date.now() < deadline) {
 51→    await new Promise((r) => setTimeout(r, 4000));
 52→
 53→    // Re-check entry still exists
 54→    if (!activeSessions.has(sessionKey)) return;
 55→
 56→    try {
 57→      const status = await pollSelfStatus(currentToken);
 58→      console.log("[agent-id/poll] Stage:", status.stage);
 59→
 60→      // Update rolling token if provided
 61→      if (status.sessionToken) {
 62→        currentToken = status.sessionToken;
 63→        entry.sessionToken = currentToken;
 64→      }
 65→
 66→      if (status.stage === "completed") {
 67→        entry.result = {
 68→          status: "completed",
 69→          agentId: status.agentId,
 70→          agentAddress: status.agentAddress || entry.agentAddress,
 71→          txHash: status.txHash,
 72→        };
 73→        return;
 74→      }
 75→
 76→      if (status.stage === "failed") {
 77→        entry.error = "Registration failed on-chain";
 78→        entry.result = { status: "failed" };
 79→        return;
 80→      }
 81→
 82→      if (status.stage === "expired") {
 83→        entry.error = "Session expired";
 84→        entry.result = { status: "failed" };
 85→        return;
 86→      }
 87→    } catch (err) {
 88→      const msg = err instanceof Error ? err.message : "Poll error";
 89→      console.error("[agent-id/poll] Error:", msg);
 90→      // Don't fail on transient errors, keep polling
 91→    }
 92→  }
 93→
 94→  entry.error = "Registration timed out (5 min)";
 95→  entry.result = { status: "failed" };
 96→}
 97→
 98→export async function POST(req: NextRequest) {
 99→  try {
100→    const { humanAddress, agentName } = await req.json();
101→
102→    if (!humanAddress) {
103→      return NextResponse.json(
104→        { error: "Missing humanAddress" },
105→        { status: 400 }
106→      );
107→    }
108→
109→    console.log("[agent-id/register] Starting for", humanAddress);
110→
111→    const session = await requestRegistration({
112→      mode: "linked",
113→      network: "mainnet",
114→      humanAddress,
115→      agentName: agentName || "OpenClaw Lending Agent",
116→      agentDescription:
117→        "Microlending agent on Celo with Self-verified identity",
118→      disclosures: {
119→        minimumAge: 18,
120→        ofac: true,
121→      },
122→      apiBase: SELF_API_BASE,
123→    });
124→
125→    console.log("[agent-id/register] Session created:", {
126→      stage: session.stage,
127→      agentAddress: session.agentAddress,
128→    });
129→
130→    const sessionKey = crypto.randomUUID();
131→
132→    activeSessions.set(sessionKey, {
133→      sessionToken: session.sessionToken,
134→      agentAddress: session.agentAddress,
135→      result: null,
136→      error: null,
137→    });
138→
139→    // Start background polling with correct Bearer auth
140→    backgroundPoll(sessionKey);
141→
142→    return NextResponse.json({
143→      sessionKey,
144→      deepLink: session.deepLink,
145→      agentAddress: session.agentAddress,
146→      expiresAt: session.expiresAt,
147→      stage: session.stage,
148→      humanInstructions: session.humanInstructions,
149→    });
150→  } catch (err) {
151→    const message =
152→      err instanceof Error ? err.message : "Registration failed";
153→    console.error("[agent-id/register] POST error:", message);
154→    return NextResponse.json({ error: message }, { status: 500 });
155→  }
156→}
