 26→export async function createService(
 27→  projectId: string,
 28→  name: string,
 29→  repo: string,
 30→  branch: string = "main",
 31→  rootDirectory: string = "apps/agent"
 32→): Promise<{ serviceId: string; environmentId: string }> {
 33→  // Get the default environment for this project
 34→  const projData = await gql<{
 35→    project: { environments: { edges: { node: { id: string } }[] } };
 36→  }>(
 37→    `query($id: String!) {
 38→      project(id: $id) {
 39→        environments { edges { node { id } } }
 40→      }
 41→    }`,
 42→    { id: projectId }
 43→  );
 44→
 45→  const environmentId = projData.project.environments.edges[0]?.node.id;
 46→  if (!environmentId) throw new Error("No environment found for project");
 47→
 48→  // Create service with repo source
 49→  const data = await gql<{ serviceCreate: { id: string } }>(
 50→    `mutation($input: ServiceCreateInput!) {
 51→      serviceCreate(input: $input) { id }
 52→    }`,
 53→    {
 54→      input: {
 55→        projectId,
 56→        name,
 57→        source: { repo },
 58→      },
 59→    }
 60→  );
 61→
 62→  const serviceId = data.serviceCreate.id;
 63→
 64→  // Connect repo with branch
 65→  await gql(
 66→    `mutation($id: String!, $input: ServiceConnectInput!) {
 67→      serviceConnect(id: $id, input: $input) { id }
 68→    }`,
 69→    {
 70→      id: serviceId,
 71→      input: { repo, branch },
 72→    }
 73→  );
 74→
 75→  // Set root directory and dockerfile path
 76→  await gql(
 77→    `mutation($serviceId: String!, $environmentId: String!, $input: ServiceInstanceUpdateInput!) {
 78→      serviceInstanceUpdate(serviceId: $serviceId, environmentId: $environmentId, input: $input)
 79→    }`,
 80→    {
 81→      serviceId,
 82→      environmentId,
 83→      input: {
 84→        rootDirectory,
 85→      },
 86→    }
 87→  );
 88→
 89→  return { serviceId, environmentId };
 90→}
