 79→export function AgentMetadataForm({
 80→  agentId,
 81→  agentName,
 82→  onSuccess,
 83→}: AgentMetadataFormProps) {
 84→  const { address } = useAccount();
 85→  const { writeContractAsync } = useWriteContract();
 86→  const { switchChainAsync } = useSwitchChain();
 87→
 88→  const [description, setDescription] = useState("");
 89→  const [x402Support, setX402Support] = useState(false);
 90→  const [services, setServices] = useState<ServiceEntry[]>([
 91→    { name: "web", endpoint: "" },
 92→  ]);
 93→
 94→  const [uploading, setUploading] = useState(false);
 95→  const [error, setError] = useState<string | null>(null);
 96→  const [arweaveUrl, setArweaveUrl] = useState<string | null>(null);
 97→
 98→  const addService = () => {
 99→    setServices([...services, { name: "", endpoint: "" }]);
100→  };
101→
102→  const removeService = (idx: number) => {
103→    setServices(services.filter((_, i) => i !== idx));
104→  };
105→
106→  const updateService = (
107→    idx: number,
108→    field: keyof ServiceEntry,
109→    value: string
110→  ) => {
111→    setServices(
112→      services.map((s, i) => (i === idx ? { ...s, [field]: value } : s))
113→    );
114→  };
115→
116→  const handleSubmit = async () => {
117→    if (!address || !description.trim()) return;
118→    setUploading(true);
119→    setError(null);
120→
121→    try {
122→      // Build EIP-8004 compliant metadata
123→      const validServices = services.filter(
124→        (s) => s.name.trim() && s.endpoint.trim()
125→      );
126→
127→      const metadata = {
128→        type: "https://eips.ethereum.org/EIPS/eip-8004#registration-v1",
129→        name: agentName,
130→        description: description.trim(),
131→        services: validServices.map((s) => {
132→          const entry: Record<string, string> = {
133→            name: s.name,
134→            endpoint: s.endpoint,
135→          };
136→          if (s.version?.trim()) entry.version = s.version.trim();
137→          return entry;
138→        }),
139→        x402Support,
140→        active: true,
141→        registrations: [
142→          {
143→            agentId,
144→            agentRegistry: `eip155:42220:${REGISTRY_ADDRESS}`,
145→          },
146→        ],
147→        supportedTrust: ["reputation"],
148→      };
149→
150→      // Upload to Arweave via Irys (free < 100KiB)
151→      const uri = await uploadToArweave(metadata);
152→      setArweaveUrl(uri);
153→
154→      // Call setAgentURI on registry
155→      await switchChainAsync({ chainId: celo.id });
156→      await writeContractAsync({
157→        address: REGISTRY_ADDRESS,
158→        abi: REGISTRY_ABI,
159→        functionName: "setAgentURI",
160→        chainId: celo.id,
161→        args: [BigInt(agentId), uri],
162→      });
163→
164→      onSuccess();
165→    } catch (err) {
166→      console.error("Metadata upload failed:", err);
167→      setError(err instanceof Error ? err.message : "Failed to set metadata");
168→    } finally {
169→      setUploading(false);
170→    }
171→  };
172→
173→  return (
