 1→import { NextRequest, NextResponse } from "next/server";
 2→
 3→interface VerificationPayload {
 4→  userId: string;
 5→  credentialSubject: {
 6→    minimumAge?: boolean;
 7→    ofac?: boolean;
 8→  };
 9→  proof: unknown;
10→}
11→
12→// In-memory store for verified users (replace with DB in production)
13→const verifiedUsers = new Map<
14→  string,
15→  { verifiedAt: string; disclosures: Record<string, boolean> }
16→>();
17→
18→export async function POST(req: NextRequest) {
19→  try {
20→    const body: VerificationPayload = await req.json();
21→
22→    if (!body.userId) {
23→      return NextResponse.json(
24→        { error: "Missing userId (wallet address)" },
25→        { status: 400 }
26→      );
27→    }
28→
29→    // TODO: Verify the Self proof on-chain or via Self SDK verification
30→    // For now, we trust the callback from Self app and store the result
31→
32→    verifiedUsers.set(body.userId.toLowerCase(), {
33→      verifiedAt: new Date().toISOString(),
34→      disclosures: {
35→        minimumAge: body.credentialSubject?.minimumAge ?? false,
36→        ofac: body.credentialSubject?.ofac ?? false,
37→      },
38→    });
39→
40→    console.log(`[verify] User verified: ${body.userId}`);
41→
42→    return NextResponse.json({
43→      success: true,
44→      userId: body.userId,
45→      verified: true,
46→    });
47→  } catch (err) {
48→    const message =
49→      err instanceof Error ? err.message : "Verification failed";
50→    console.error("[verify] Error:", message);
51→    return NextResponse.json({ error: message }, { status: 500 });
52→  }
53→}
54→
55→export async function GET(req: NextRequest) {
56→  const address = req.nextUrl.searchParams.get("address");
57→
58→  if (!address) {
59→    return NextResponse.json(
60→      { error: "Missing address parameter" },
61→      { status: 400 }
62→    );
63→  }
64→
65→  const verification = verifiedUsers.get(address.toLowerCase());
66→
67→  return NextResponse.json({
68→    verified: !!verification,
69→    ...(verification || {}),
70→  });
71→}
